
#include <c2goto/cprover_library.h>
#include <util/language.h>
#include <util/filesystem.h>
#include <util/message.h>

extern "C"
{
#include <libc.h>
#include <libm.h>
#include <headers/libc_hdr.h>
#undef ESBMC_FLAIL
}

/* This class represents the extracted internal libc. It uses the headers
 * generated by the build system to dump the bundled libc/libm files in a
 * cached directory. The headers contain invocations of the form
 * ESBMC_FLAIL(body, size, hash, name) for each bundled file,
 * see scripts/flail.py --macro. */
static class
{
  file_operations::tmp_path base;
  std::string headers;

  /* Digests of every bundled source and header, emitted next to the arrays by
   * scripts/flail.py, so this key tracks any edit to any of them. */
  static std::string content_key()
  {
    std::string key;
#define ESBMC_FLAIL(body, size, hash, ...) key += hash;
#include <libc.h>
#include <libm.h>
#include <headers/libc_hdr.h>
#undef ESBMC_FLAIL
    return key;
  }

  /* Both trees are written together: unlike the previous per-tree laziness
   * this runs at most once per build, since the result is cached. */
  static void extract(const std::string &root)
  {
    /* The path variables are only read inside the ESBMC_FLAIL expansions of
     * the generated includes, which cppcheck cannot resolve. */
    // cppcheck-suppress unreadVariable
    const std::string headers = root + "/headers";
#define ESBMC_FLAIL(body, size, hash, ...)                                     \
  file_operations::create_path_and_write(                                      \
    headers + "/" #__VA_ARGS__, body, size);
#include <headers/libc_hdr.h>
#undef ESBMC_FLAIL

    const std::string libc = root + "/library";
#define ESBMC_FLAIL(body, size, hash, ...)                                     \
  file_operations::create_path_and_write(libc + "/" #__VA_ARGS__, body, size);
#include <libc.h>
#undef ESBMC_FLAIL

    // cppcheck-suppress unreadVariable
    const std::string libm = libc + "/libm";
#define ESBMC_FLAIL(body, size, hash, ...)                                     \
  file_operations::create_path_and_write(libm + "/" #__VA_ARGS__, body, size);
#include <libm.h>
#undef ESBMC_FLAIL
  }

  const std::string &base_path()
  {
    if (base.path() == "")
      base =
        file_operations::cached_extract_dir("libc", content_key(), extract);
    return base.path();
  }

public:
  const std::string &header_dir()
  {
    if (headers == "")
      headers = base_path() + "/headers";
    return headers;
  }

  template <typename F>
  void foreach_libc_libm(F &&f [[maybe_unused]])
  {
    const std::string libc = base_path() + "/library";
#define ESBMC_FLAIL(body, size, hash, ...) f(libc + "/" #__VA_ARGS__);
#include <libc.h>
#undef ESBMC_FLAIL

    // cppcheck-suppress unreadVariable
    const std::string libm = libc + "/libm";
#define ESBMC_FLAIL(body, size, hash, ...) f(libm + "/" #__VA_ARGS__);
#include <libm.h>
#undef ESBMC_FLAIL
  }
} internal_libc;

const std::string *internal_libc_header_dir()
{
  return config.ansi_c.lib == configt::ansi_ct::libt::LIB_NONE
           ? nullptr
           : &internal_libc.header_dir();
}

/* copy of clang_c_convertert::get_filename_from_path(); TODO: unify */
static std::string get_filename_from_path(const std::string &path)
{
  if (path.find_last_of('/') != std::string::npos)
    return path.substr(path.find_last_of('/') + 1);

  return path;
}

void add_bundled_library_sources(contextt &context, const languaget &c_language)
{
  /* First extract headers (if not already done) */
  if (internal_libc_header_dir())
  {
    bool skip_fenv = false;
#ifdef ESBMC_CHERI_CLANG_MORELLO
    /* Morello is hard-float, which has an incompatible <fenv.h> */
    skip_fenv = config.ansi_c.cheri != configt::ansi_ct::CHERI_OFF;
#endif

    /* Next, extract (if not already done) and process every libc/libm file. */
    internal_libc.foreach_libc_libm([&](const std::string &path) {
      if (skip_fenv && get_filename_from_path(path) == "fenv.c")
        return;
      languaget *l = c_language.new_language();
      log_status("file {}: Parsing", path);
      if (l->parse(path) || l->typecheck(context, path))
      {
        log_error("error processing internal libc source {}", path);
        abort();
      }
      delete l;
    });
  }
}
